FUNCTION ModusPonens(premise1, premise2):
 // premise1 is implication p→q
 // premise2 is p (antecedent)
 IF premise1.consequent == premise2 THEN
 RETURN premise1.consequent
 ELSE
 RETURN "Cannot apply Modus Ponens"
 END IF

// Example: p→q = "If it rains, ground is wet"
// p = "It rains"
// Conclusion: "Ground is wet"

FUNCTION ModusTollens(premise1, premise2):
 // premise1 is implication p→q
 // premise2 is ¬q (negation of consequent)
 IF premise1.consequent != premise2 THEN
 // Need negation of consequent
 RETURN premise1.antecedent.negate()
 ELSE
 RETURN "Cannot apply Modus Tollens"
 END IF

// Example: p→q = "If it rains, ground is wet"
// ¬q = "Ground is not wet"
// Conclusion: "It did not rain"

FUNCTION HypotheticalSyllogism(implication1, implication2):
 // implication1: p→q
 // implication2: q→r
 // Result: p→r

 new_antecedent = implication1.antecedent
 new_consequent = implication2.consequent

 RETURN Implication(new_antecedent, new_consequent)

// Example chain:
// 1. If study(p) → pass(q)
// 2. If pass(q) → graduate(r)
// Conclusion: If study(p) → graduate(r)
